import React, { useState, useEffect, useRef } from 'react';
import api from '../api';
import './Reports.css';

export default function Reports() {
  const [results, setResults] = useState([]);
  const [loading, setLoading] = useState(true);
  const [uploading, setUploading] = useState(false);
  const [activeUploadId, setActiveUploadId] = useState(null);
  const [selectedResult, setSelectedResult] = useState(null);
  const fileInputRef = useRef(null);

  useEffect(() => {
    api.get('/results/my-results')
      .then(res => setResults(res.data))
      .catch(() => setResults([]))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="page-loading">Loading...</div>;

  const handleFileChange = async (e) => {
    const file = e.target.files[0];
    if (!file || !activeUploadId) return;

    const formData = new FormData();
    formData.append('assignment', file);

    setUploading(true);
    try {
      await api.post(`/results/upload-assignment/${activeUploadId}`, formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      alert('Assignment uploaded successfully!');
      // Refresh results
      const res = await api.get('/results/my-results');
      setResults(res.data);
    } catch (err) {
      console.error(err);
      const msg = err.response?.data?.message || 'Failed to upload assignment.';
      alert(msg);
    } finally {
      setUploading(false);
      setActiveUploadId(null);
      e.target.value = null; // Clear input
    }
  };

  const totalTests = results.length;
  const avgScore = totalTests
    ? Math.round(results.reduce((acc, r) => acc + r.percentage, 0) / totalTests)
    : 0;
  const bestScore = totalTests
    ? Math.max(...results.map(r => r.percentage))
    : 0;

  return (
    <div className="reports-page">
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleFileChange}
        style={{ display: 'none' }}
      />
      <h1 className="page-title">Reports</h1>
      <p className="page-desc">Your assignment history and performance overview.</p>

      <div className="reports-summary">
        <div className="summary-card glass-card">
          <span className="summary-label">Total Tests</span>
          <div className="summary-value">{totalTests}</div>
        </div>
        <div className="summary-card glass-card">
          <span className="summary-label">Average Score</span>
          <div className="summary-value">{avgScore}%</div>
        </div>
        <div className="summary-card glass-card">
          <span className="summary-label">Best Score</span>
          <div className="summary-value">{bestScore}%</div>
        </div>
      </div>

      <div className="reports-table-wrap glass-card">
        {results.length ? (
          <table className="reports-table">
            <thead>
              <tr>
                <th>Subject</th>
                <th className="col-score">Score</th>
                <th className="col-date">Date</th>
                <th className="col-action">Assignment</th>
              </tr>
            </thead>
            <tbody>
              {results.map((r) => (
                <tr key={r._id}>
                  <td>
                    <strong
                      className="subject-link"
                      style={{ cursor: 'pointer', color: '#10b981' }}
                      onClick={() => setSelectedResult(r)}
                    >
                      {r.subject?.name}
                    </strong>
                  </td>
                  <td className="col-score"><strong>{r.percentage}%</strong> ({r.score}/{r.totalQuestions})</td>
                  <td className="col-date">{new Date(r.completedAt).toLocaleString()}</td>
                  <td className="col-action">
                    {r.assignmentFile ? (
                      <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                        <a
                          href={`/uploads/${r.assignmentFile}`}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="view-btn-mini"
                          style={{ display: 'flex', gap: '8px', alignItems: 'center', width: 'auto', padding: '0 8px', textDecoration: 'none' }}
                          title="View Assignment"
                          onClick={(e) => e.stopPropagation()}
                        >
                          <span className="status-badge success">Uploaded</span>
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ width: 16, height: 16 }}>
                            <path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"></path>
                            <circle cx="12" cy="12" r="3"></circle>
                          </svg>
                        </a>
                        <button
                          className={`upload-btn-mini ${uploading && activeUploadId === r._id ? 'uploading' : ''}`}
                          onClick={(e) => {
                            e.stopPropagation();
                            setActiveUploadId(r._id);
                            fileInputRef.current.click();
                          }}
                          disabled={uploading}
                          title="Replace Assignment"
                        >
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ width: 16, height: 16 }}>
                            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                            <polyline points="17 8 12 3 7 8"></polyline>
                            <line x1="12" y1="3" x2="12" y2="15"></line>
                          </svg>
                        </button>
                      </div>
                    ) : (
                      <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
                        <span className="status-badge">No File</span>
                        <button
                          className={`upload-btn-mini ${uploading && activeUploadId === r._id ? 'uploading' : ''}`}
                          onClick={(e) => {
                            e.stopPropagation();
                            setActiveUploadId(r._id);
                            fileInputRef.current.click();
                          }}
                          disabled={uploading}
                          title="Upload Assignment"
                        >
                          <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" style={{ width: 16, height: 16 }}>
                            <path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"></path>
                            <polyline points="17 8 12 3 7 8"></polyline>
                            <line x1="12" y1="3" x2="12" y2="15"></line>
                          </svg>
                        </button>
                      </div>
                    )}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        ) : (
          <p className="no-data">No results yet. Take an assignment from My Assignments.</p>
        )}
      </div>

      {selectedResult && (
        <div className="modal-overlay" onClick={() => setSelectedResult(null)}>
          <div className="modal glass-card" onClick={e => e.stopPropagation()}>
            <div className="modal-header">
              <h3>Assignment Result</h3>
              <button className="btn-close" onClick={() => setSelectedResult(null)}>✕</button>
            </div>
            <div className="modal-body">
              <div className="result-summary">
                <div className="summary-item">
                  <label>Subject</label>
                  <span>{selectedResult.subject?.name}</span>
                </div>
                <div className="summary-item">
                  <label>Assignment</label>
                  <span>{selectedResult.assessment?.title}</span>
                </div>
                <div className="summary-item">
                  <label>Score</label>
                  <span className="score-high">{selectedResult.percentage}%</span>
                </div>
                <div className="summary-item">
                  <label>Completed On</label>
                  <span>{new Date(selectedResult.completedAt).toLocaleString()}</span>
                </div>
              </div>

              <div className="result-details">
                <h4>Performance Breakdown</h4>
                <p>You answered <strong>{selectedResult.score}</strong> correct out of <strong>{selectedResult.totalQuestions}</strong> questions.</p>
                <div className="progress-bar-wrap">
                  <div className="progress-bar-fill" style={{ width: `${selectedResult.percentage}%` }}></div>
                </div>
              </div>
            </div>
            <div className="modal-footer">
              <button className="btn btn-primary" onClick={() => setSelectedResult(null)}>Close</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
